+/// File-based counterpart to `write_excel_bytes_with_options`.
+pub fn write_excel_with_options(
+    frame: &DataFrame,
+    path: &Path,
+    options: &ExcelWriteOptions,
+) -> Result<(), IoError> {
+    let bytes = write_excel_bytes_with_options(frame, options)?;
+    std::fs::write(path, bytes)?;
+    Ok(())
+}
